// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.eclipse.rdf4j.sail.lmdb.evaluation.LmdbNativeAggregateCompiler.UNKNOWN;

import java.io.IOException;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.concurrent.atomic.AtomicLong;

import org.eclipse.rdf4j.common.annotation.Experimental;

/**
 * Worst-case-optimal join (leapfrog triejoin) over a cyclic sub-bag of a {@code MultiJoinPlan}. Instead of joining
 * statement patterns pairwise — which materializes an intermediate as large as the worst pairwise product — the
 * leapfrog intersects all patterns one variable at a time, so no intermediate ever exceeds the final result bound.
 *
 * <p>
 * Recognition: over the flattened inner-join bag, eligible {@link PatternPlan} children whose free slots (not bound by
 * the entry row) form a cyclic hypergraph — detected by GYO ear reduction — become one {@link LeapfrogPlan}; every
 * other child, and every filter, keeps its ordinary treatment around it. This is what confines the worst-case-optimal
 * strategy to exactly the query part that needs it.
 *
 * <p>
 * Execution: per entry row the cursor picks a greedy variable order over the still-unbound core slots, then walks them
 * depth-first. At each depth it materializes, for every core pattern containing that variable, the sorted distinct
 * values the pattern allows under the current prefix (a "frontier": one bounded index scan), intersects the frontiers,
 * and binds each surviving value in turn. A solution's multiplicity — several stored quads matching one visible
 * binding, possible only through an unrestricted or multi-graph context position — is the product of duplicate counts
 * collected while deduplicating each pattern's final-level frontier, so no extra witness scans are needed.
 *
 * <p>
 * Planned per the ExecPlan {@code plans/lmdb-native-engine/16-wcoj-leapfrog-and-codegen.md}.
 */
@Experimental
final class LmdbNativeLeapfrogJoin {

	static final String ENABLED_PROPERTY = "rdf4j.lmdb.wcoj.enabled";
	static final String PARALLEL_MIN_CANDIDATES_PROPERTY = "rdf4j.lmdb.wcoj.parallelMinCandidates";
	/** Cyclic cores larger than this are left to the ordinary strategies (recognition cost sanity bound). */
	private static final int MAX_CORE_PATTERNS = 16;

	/** Times a cyclic sub-bag was recognized and replaced by a leapfrog plan. Test hook. */
	static final AtomicLong PLANNED = new AtomicLong();
	/** Times a leapfrog cursor was opened for execution. Test hook. */
	static final AtomicLong OPENED = new AtomicLong();
	/** Times a leapfrog executed its levels across parallel workers. Test hook. */
	static final AtomicLong PARALLEL_RUNS = new AtomicLong();

	private LmdbNativeLeapfrogJoin() {
	}

	static boolean enabled() {
		return !"false".equalsIgnoreCase(System.getProperty(ENABLED_PROPERTY));
	}

	static void resetMetrics() {
		PLANNED.set(0);
		OPENED.set(0);
		PARALLEL_RUNS.set(0);
	}

	/**
	 * Attempts to open the whole multi-join as [bounded input children] → leapfrog(core) → [remaining children], with
	 * the bag's filters attached at the earliest depth whose slots are covered. Returns null when no eligible cyclic
	 * core exists — the caller then falls through to the ordinary strategy ladder.
	 */
	static RowCursor tryOpen(MultiJoinPlan multiJoin, RowState row) throws IOException {
		if (!enabled()) {
			return null;
		}
		SlotPlan[] children = multiJoin.children;
		long boundMask = row.boundMask();
		boolean[] core = findCyclicCore(children, boundMask);
		if (core == null) {
			return null;
		}
		PLANNED.incrementAndGet();

		ArrayList<PatternPlan> corePatterns = new ArrayList<>();
		long coreProduced = 0L;
		for (int i = 0; i < children.length; i++) {
			if (core[i]) {
				corePatterns.add((PatternPlan) children[i]);
				coreProduced |= children[i].producedMask();
			}
		}

		// stage order: keep the compiler's cost-derived child order, with the whole core fused into one
		// leapfrog stage at the position of the first core member. Selective non-core children the compiler
		// ranked before the cycle (VALUES, bound attribute probes) still run first and pre-bind core slots,
		// which keeps the leapfrog's search confined to the surviving bindings.
		SlotPlan[] derivedOrder = multiJoin.derivedPlan(boundMask).order;
		long preStageProduced = 0L;
		boolean beforeCore = true;
		for (SlotPlan child : derivedOrder) {
			if (isCoreMember(core, children, child)) {
				beforeCore = false;
			} else if (beforeCore) {
				preStageProduced |= child.producedMask();
			}
		}

		// filters that touch a core slot and whose whole read-set is bound once the leapfrog row exists run
		// INSIDE the leapfrog, at the earliest level that covers them — pruning subtrees during the search
		// instead of discarding finished rows. The rest keep their ordinary chain placement.
		long coveredByLeapfrog = boundMask | preStageProduced | coreProduced;
		ArrayList<MaskedFilter> pushed = new ArrayList<>();
		ArrayList<MaskedFilter> chained = new ArrayList<>();
		for (MaskedFilter filter : multiJoin.filters) {
			if (filter.mask >= 0L && (filter.mask & coreProduced) != 0L
					&& (filter.mask & ~coveredByLeapfrog) == 0L) {
				pushed.add(filter);
			} else {
				chained.add(filter);
			}
		}

		LeapfrogPlan leapfrog = new LeapfrogPlan(corePatterns.toArray(PatternPlan[]::new),
				pushed.toArray(MaskedFilter[]::new));
		ArrayList<SlotPlan> stages = new ArrayList<>(children.length);
		boolean corePlaced = false;
		for (SlotPlan child : derivedOrder) {
			if (isCoreMember(core, children, child)) {
				if (!corePlaced) {
					stages.add(leapfrog);
					corePlaced = true;
				}
			} else {
				stages.add(child);
			}
		}

		return openChain(stages, chained.toArray(MaskedFilter[]::new), boundMask, row);
	}

	private static boolean isCoreMember(boolean[] core, SlotPlan[] children, SlotPlan child) {
		for (int i = 0; i < children.length; i++) {
			if (core[i] && children[i] == child) {
				return true;
			}
		}
		return false;
	}

	/**
	 * JoinCursor chain over the stage order with earliest-cover filter placement, mirroring MultiJoinPlan.openChain.
	 */
	private static RowCursor openChain(List<SlotPlan> stages, MaskedFilter[] filters, long boundMask, RowState row)
			throws IOException {
		int n = stages.size();
		long[] cumulative = new long[n];
		long bound = boundMask;
		for (int d = 0; d < n; d++) {
			bound |= stages.get(d).producedMask();
			cumulative[d] = bound;
		}
		int[] filterDepth = new int[filters.length];
		for (int f = 0; f < filters.length; f++) {
			long mask = filters[f].mask;
			int depth = n - 1;
			if (mask >= 0L) {
				for (int d = 0; d < n; d++) {
					if ((mask & ~cumulative[d]) == 0L) {
						depth = d;
						break;
					}
				}
			}
			filterDepth[f] = depth;
		}
		RowCursor cursor = stages.get(0).open(row);
		try {
			cursor = applyFilters(cursor, filters, filterDepth, 0, row);
			long leftProduced = stages.get(0).producedMask();
			for (int i = 1; i < n; i++) {
				cursor = new JoinCursor(cursor, stages.get(i), row, leftProduced);
				cursor = applyFilters(cursor, filters, filterDepth, i, row);
				leftProduced |= stages.get(i).producedMask();
			}
			return cursor;
		} catch (RuntimeException | Error problem) {
			cursor.close();
			throw problem;
		}
	}

	private static RowCursor applyFilters(RowCursor cursor, MaskedFilter[] filters, int[] filterDepth, int depth,
			RowState row) {
		for (int i = 0; i < filterDepth.length; i++) {
			if (filterDepth[i] == depth) {
				cursor = new FilterCursor(cursor, filters[i].filter, row);
			}
		}
		return cursor;
	}

	/**
	 * GYO ear reduction over the eligible patterns' free-slot hypergraph: repeatedly drop vertices that occur in at
	 * most one remaining edge and edges subsumed by another remaining edge. What survives is the cyclic core; an empty
	 * remainder means the bag is (alpha-)acyclic and the ordinary join strategies keep it. Returns a per-child core
	 * membership mask, or null when there is no usable core.
	 */
	private static boolean[] findCyclicCore(SlotPlan[] children, long boundMask) {
		int n = children.length;
		if (n < 3) {
			return null;
		}
		long[] free = new long[n];
		boolean[] alive = new boolean[n];
		int eligible = 0;
		for (int i = 0; i < n; i++) {
			if (!(children[i]instanceof PatternPlan pattern)) {
				continue;
			}
			if (!eligibleCorePattern(pattern)) {
				continue;
			}
			long freeMask = pattern.producedMask() & ~boundMask;
			if (Long.bitCount(freeMask) == 0) {
				continue;
			}
			free[i] = freeMask;
			alive[i] = true;
			eligible++;
		}
		if (eligible < 3) {
			return null;
		}
		boolean changed = true;
		while (changed) {
			changed = false;
			// vertex occurrence counts over the remaining edges
			long once = 0L;
			long twice = 0L;
			for (int i = 0; i < n; i++) {
				if (alive[i]) {
					twice |= once & free[i];
					once |= free[i];
				}
			}
			long earVertices = once & ~twice;
			if (earVertices != 0L) {
				for (int i = 0; i < n; i++) {
					if (alive[i] && (free[i] & earVertices) != 0L) {
						free[i] &= ~earVertices;
						changed = true;
					}
				}
			}
			for (int i = 0; i < n; i++) {
				if (!alive[i]) {
					continue;
				}
				if (free[i] == 0L) {
					alive[i] = false;
					changed = true;
					continue;
				}
				for (int j = 0; j < n; j++) {
					if (i != j && alive[j] && (free[i] & ~free[j]) == 0L) {
						// an edge subsumed by another is an ear; drop the smaller (ties: higher index)
						if (free[i] != free[j] || i > j) {
							alive[i] = false;
							changed = true;
							break;
						}
					}
				}
			}
		}
		int coreSize = 0;
		for (int i = 0; i < n; i++) {
			if (alive[i]) {
				coreSize++;
			}
		}
		if (coreSize < 3 || coreSize > MAX_CORE_PATTERNS) {
			return null;
		}
		return alive;
	}

	private static boolean eligibleCorePattern(PatternPlan pattern) {
		if (pattern.hasRepeatedSlot() || pattern.statementOrder != null || pattern.range != null
				|| pattern.namedContextScope || pattern.contexts.isEmpty()) {
			return false;
		}
		// bind-constant terms bind their slot from the quad during ordinary evaluation; the leapfrog does
		// not replay that side effect, so such patterns stay outside the core
		return !bindsConstantSlot(pattern.s) && !bindsConstantSlot(pattern.p) && !bindsConstantSlot(pattern.o)
				&& !bindsConstantSlot(pattern.c);
	}

	private static boolean bindsConstantSlot(Term term) {
		return term.bindConstant;
	}

	/**
	 * The fused worst-case-optimal stage: produces every binding of the core's slots, with multiplicity. One instance
	 * lives for one query execution (created per {@link #tryOpen}), so it may carry a mutable frontier cache: a
	 * frontier depends only on the pattern's resolved scan terms, and the expensive ones — patterns none of whose terms
	 * are bound by the current prefix, whose frontier is identical for every prefix — hit the cache after the first
	 * computation instead of rescanning per prefix.
	 */
	@Experimental
	static final class LeapfrogPlan implements SlotPlan {
		/** Total cached values across all frontiers before caching stops (memory bound; entries are never evicted). */
		private static final long MAX_CACHED_VALUES = 8L << 20;

		final PatternPlan[] patterns;
		/** Filters fully covered once the leapfrog row exists; evaluated at their earliest covering level. */
		final MaskedFilter[] filters;
		final long producedMask;
		/** Concurrent: parallel workers share this cache (frontiers are immutable; duplicate computes are benign). */
		private final java.util.concurrent.ConcurrentHashMap<FrontierKey, Frontier> frontierCache = new java.util.concurrent.ConcurrentHashMap<>();
		private final AtomicLong cachedValues = new AtomicLong();

		LeapfrogPlan(PatternPlan[] patterns) {
			this(patterns, new MaskedFilter[0]);
		}

		LeapfrogPlan(PatternPlan[] patterns, MaskedFilter[] filters) {
			this.patterns = patterns;
			this.filters = filters;
			long mask = 0L;
			for (PatternPlan pattern : patterns) {
				mask |= pattern.producedMask();
			}
			this.producedMask = mask;
		}

		/**
		 * Shared cache for PREFIX-INDEPENDENT frontiers only: scans none of whose terms came from a runtime-bound slot.
		 * Those are identical for every prefix, every reopen and every parallel worker, and there are at most a handful
		 * per core. Prefix-dependent frontiers are memoized per level instead (see {@link Level}): the search is
		 * depth-first, so their reuse is always "same resolved key as the previous entry at this level".
		 */
		Frontier constantFrontier(int patternIndex, int slot, RowState row, boolean needCounts,
				NativeLmdbQuerySource.NativeProbe probe) throws IOException {
			PatternPlan pattern = patterns[patternIndex];
			FrontierKey key = new FrontierKey(patternIndex, pattern.s.lookup(row.slots), pattern.p.lookup(row.slots),
					pattern.o.lookup(row.slots), pattern.c.lookup(row.slots),
					pattern.quadPositionOfSlot(slot), needCounts);
			Frontier cached = frontierCache.get(key);
			if (cached != null) {
				return cached;
			}
			Frontier frontier = scanFrontier(pattern, slot, row, needCounts, probe);
			if (cachedValues.get() + frontier.values.length <= MAX_CACHED_VALUES) {
				if (frontierCache.putIfAbsent(key, frontier) == null) {
					cachedValues.addAndGet(frontier.values.length);
				}
			}
			return frontier;
		}

		/** Whether any of the pattern's terms is resolved from a slot the row currently binds. */
		boolean hasRuntimeBoundTerm(int patternIndex, RowState row) {
			return patterns[patternIndex].hasRuntimeBoundSlot(row);
		}

		@Override
		public RowCursor open(RowState row) {
			OPENED.incrementAndGet();
			return new LeapfrogCursor(this, row);
		}

		@Override
		public long producedMask() {
			return producedMask;
		}

		@Override
		public double estimate(RowState row) {
			double estimate = 1D;
			for (PatternPlan pattern : patterns) {
				double child = pattern.estimate(row);
				if (!Double.isFinite(child)) {
					return Double.POSITIVE_INFINITY;
				}
				estimate *= Math.max(1D, child);
			}
			return estimate;
		}
	}

	/** Cache key: pattern identity plus its four resolved scan ids, the streamed position, and the counts flag. */
	private record FrontierKey(int pattern, long subj, long pred, long obj, long context, int position,
			boolean counts) {
	}

	/**
	 * Depth-first leapfrog over the core's unbound slots. Levels are entered by materializing and intersecting each
	 * participating pattern's frontier under the current prefix; leaves emit once per solution multiplicity.
	 */
	static final class LeapfrogCursor implements RowCursor {
		private final LeapfrogPlan plan;
		private final RowState row;
		/** Lazily created reusable probes, one per core pattern, so prefix-bound scans reuse LMDB cursor machinery. */
		private final NativeLmdbQuerySource.NativeProbe[] probes;
		private Level[] levels;
		private NativeBooleanFilter[] openCoveredFilters;
		private ParallelLeapfrog parallel;
		private int depth = -1;
		private long pendingMultiplicity;
		private boolean initialized;
		private boolean exhausted;

		/** Set on parallel-worker cursors: a worker's leapfrog must never spawn nested parallel runs. */
		private final boolean allowParallel;
		/** The core filters this cursor evaluates (worker cursors receive worker-confined forks). */
		private final MaskedFilter[] filters;

		LeapfrogCursor(LeapfrogPlan plan, RowState row) {
			this(plan, row, true, plan.filters);
		}

		LeapfrogCursor(LeapfrogPlan plan, RowState row, boolean allowParallel) {
			this(plan, row, allowParallel, plan.filters);
		}

		LeapfrogCursor(LeapfrogPlan plan, RowState row, boolean allowParallel, MaskedFilter[] filters) {
			this.plan = plan;
			this.row = row;
			this.allowParallel = allowParallel;
			this.filters = filters;
			this.probes = new NativeLmdbQuerySource.NativeProbe[plan.patterns.length];
		}

		private NativeLmdbQuerySource.NativeProbe probe(int patternIndex) {
			NativeLmdbQuerySource.NativeProbe probe = probes[patternIndex];
			if (probe == null) {
				probe = row.source.newProbe();
				probes[patternIndex] = probe;
			}
			return probe;
		}

		@Override
		public boolean next() throws IOException {
			if (pendingMultiplicity > 0) {
				pendingMultiplicity--;
				return true;
			}
			if (exhausted) {
				return false;
			}
			if (!initialized) {
				initialized = true;
				if (!initLevels()) {
					// every core slot already bound: the core degenerates to a filter + existence check
					exhausted = true;
					if (!acceptAll(filters, row)) {
						return false;
					}
					long multiplicity = fullyBoundMultiplicity();
					if (multiplicity > 0) {
						pendingMultiplicity = multiplicity - 1;
						return true;
					}
					return false;
				}
				if (!acceptAll(openCoveredFilters, row)) {
					exhausted = true;
					return false;
				}
				depth = 0;
				if (!enterLevel(0)) {
					exhausted = true;
					return false;
				}
				if (allowParallel && levels.length >= 2) {
					parallel = ParallelLeapfrog.tryStart(plan, row, levels, filters);
				}
			}
			if (parallel != null) {
				return parallel.next();
			}
			while (depth >= 0) {
				Level level = levels[depth];
				if (!level.advance(row)) {
					depth--;
					continue;
				}
				if (depth == levels.length - 1) {
					long multiplicity = 1;
					for (int d = 0; d < levels.length; d++) {
						multiplicity *= levels[d].currentMultiplicity();
					}
					if (multiplicity <= 0) {
						continue;
					}
					pendingMultiplicity = multiplicity - 1;
					return true;
				}
				depth++;
				if (!enterLevel(depth)) {
					// empty frontier below: retreat and try the next candidate at this depth
					depth--;
				}
			}
			exhausted = true;
			return false;
		}

		/** Chooses the variable order and builds level structures. False when no slot is left unbound. */
		private boolean initLevels() {
			long freeMask = plan.producedMask & ~row.boundMask();
			int slotCount = Long.bitCount(freeMask);
			if (slotCount == 0) {
				return false;
			}
			int[] order = chooseOrder(freeMask, slotCount);
			levels = new Level[slotCount];
			long boundSoFar = row.boundMask();
			for (int d = 0; d < slotCount; d++) {
				int slot = order[d];
				ArrayList<Integer> members = new ArrayList<>();
				for (int p = 0; p < plan.patterns.length; p++) {
					if ((plan.patterns[p].producedMask() & (1L << slot)) != 0L) {
						members.add(p);
					}
				}
				int[] memberIndexes = new int[members.size()];
				boolean[] finalHere = new boolean[members.size()];
				long afterThis = boundSoFar | (1L << slot);
				for (int m = 0; m < members.size(); m++) {
					memberIndexes[m] = members.get(m);
					finalHere[m] = (plan.patterns[memberIndexes[m]].producedMask() & ~afterThis) == 0L;
				}
				levels[d] = new Level(slot, memberIndexes, finalHere);
				boundSoFar = afterThis;
			}
			// attach each core filter at the earliest level after which its whole read-set is bound; filters
			// already covered by the entry row run once before the search starts
			ArrayList<NativeBooleanFilter> preCovered = new ArrayList<>();
			for (MaskedFilter filter : filters) {
				long uncovered = filter.mask & ~row.boundMask();
				if (uncovered == 0L) {
					preCovered.add(filter.filter);
					continue;
				}
				long boundAt = row.boundMask();
				for (int d = 0; d < slotCount; d++) {
					boundAt |= 1L << order[d];
					if ((filter.mask & ~boundAt) == 0L) {
						levels[d].addFilter(filter.filter);
						break;
					}
				}
			}
			openCoveredFilters = preCovered.isEmpty() ? null
					: preCovered.toArray(NativeBooleanFilter[]::new);
			return true;
		}

		private static boolean acceptAll(MaskedFilter[] filters, RowState row) {
			for (MaskedFilter filter : filters) {
				if (!filter.filter.accept(row)) {
					return false;
				}
			}
			return true;
		}

		private static boolean acceptAll(NativeBooleanFilter[] filters, RowState row) {
			if (filters == null) {
				return true;
			}
			for (NativeBooleanFilter filter : filters) {
				if (!filter.accept(row)) {
					return false;
				}
			}
			return true;
		}

		/**
		 * Greedy order: highest pattern-connectivity first (ties: smaller summed static estimates), each subsequent
		 * slot preferring adjacency (sharing a pattern) with the slots already chosen.
		 */
		private int[] chooseOrder(long freeMask, int slotCount) {
			int[] order = new int[slotCount];
			long remaining = freeMask;
			long chosen = 0L;
			for (int d = 0; d < slotCount; d++) {
				int best = -1;
				int bestScore = -1;
				double bestEstimate = Double.POSITIVE_INFINITY;
				boolean bestAdjacent = false;
				for (long mask = remaining; mask != 0L; mask &= mask - 1) {
					int slot = Long.numberOfTrailingZeros(mask);
					int score = 0;
					double estimateSum = 0D;
					boolean adjacent = false;
					for (PatternPlan pattern : plan.patterns) {
						if ((pattern.producedMask() & (1L << slot)) == 0L) {
							continue;
						}
						score++;
						estimateSum += Double.isFinite(pattern.staticEstimate) ? pattern.staticEstimate : 1_000_000D;
						if ((pattern.producedMask() & chosen) != 0L) {
							adjacent = true;
						}
					}
					boolean better;
					if (best < 0) {
						better = true;
					} else if (chosen != 0L && adjacent != bestAdjacent) {
						better = adjacent;
					} else if (score != bestScore) {
						better = score > bestScore;
					} else {
						better = estimateSum < bestEstimate;
					}
					if (better) {
						best = slot;
						bestScore = score;
						bestEstimate = estimateSum;
						bestAdjacent = adjacent;
					}
				}
				order[d] = best;
				chosen |= 1L << best;
				remaining &= ~(1L << best);
			}
			return order;
		}

		/** Multiplicity of the fully-bound core (all slots pre-bound by the entry row): product of match counts. */
		private long fullyBoundMultiplicity() throws IOException {
			long multiplicity = 1;
			for (PatternPlan pattern : plan.patterns) {
				long count = 0;
				try (PatternCursor cursor = pattern.openRaw(row)) {
					while (cursor.next() != null) {
						count++;
					}
				}
				if (count == 0) {
					return 0;
				}
				multiplicity *= count;
			}
			return multiplicity;
		}

		private boolean enterLevel(int d) throws IOException {
			return levels[d].enter(this, row);
		}

		@Override
		public void close() {
			if (parallel != null) {
				parallel.close();
				parallel = null;
			}
			if (levels != null) {
				for (Level level : levels) {
					level.release(row);
				}
			}
			for (int i = 0; i < probes.length; i++) {
				if (probes[i] != null) {
					probes[i].close();
					probes[i] = null;
				}
			}
			exhausted = true;
		}
	}

	/** One search variable: the participating patterns, the intersected frontier, and the iteration position. */
	private static final class Level {
		private final int slot;
		/** Indexes into the plan's pattern array of the patterns containing this level's slot. */
		private final int[] members;
		/** Whether this level binds the member's last free slot — only then do duplicate counts mean multiplicity. */
		private final boolean[] finalLevel;
		private long[] values;
		private long[] multiplicities;
		private NativeBooleanFilter[] filters;
		private int position;
		private int mark = -1;
		/** Per-member last-key memo for prefix-dependent frontiers (depth-first search revisits the same key). */
		private Frontier[] memoFrontier;
		private long[] memoKeys;
		private boolean[] memoValid;

		Level(int slot, int[] members, boolean[] finalLevel) {
			this.slot = slot;
			this.members = members;
			this.finalLevel = finalLevel;
		}

		void addFilter(NativeBooleanFilter filter) {
			if (filters == null) {
				filters = new NativeBooleanFilter[] { filter };
			} else {
				filters = Arrays.copyOf(filters, filters.length + 1);
				filters[filters.length - 1] = filter;
			}
		}

		/**
		 * Resolves one member's frontier: the shared plan cache for prefix-independent scans, otherwise a per-member
		 * last-key memo — the depth-first search re-enters this level many times under the same shallower prefix, so
		 * the previous frontier is almost always the right one and no growing map is needed.
		 */
		private Frontier memberFrontier(LeapfrogCursor cursor, RowState row, int m, PatternPlan member,
				boolean needCounts) throws IOException {
			if (!member.hasRuntimeBoundSlot(row)) {
				return cursor.plan.constantFrontier(members[m], slot, row, needCounts, cursor.probe(members[m]));
			}
			if (memoFrontier == null) {
				memoFrontier = new Frontier[members.length];
				memoKeys = new long[members.length * 4];
				memoValid = new boolean[members.length];
			}
			long s = member.s.lookup(row.slots);
			long p = member.p.lookup(row.slots);
			long o = member.o.lookup(row.slots);
			long c = member.c.lookup(row.slots);
			int keyBase = m * 4;
			if (memoValid[m] && memoKeys[keyBase] == s && memoKeys[keyBase + 1] == p && memoKeys[keyBase + 2] == o
					&& memoKeys[keyBase + 3] == c) {
				return memoFrontier[m];
			}
			Frontier frontier = scanFrontier(member, slot, row, needCounts, cursor.probe(members[m]));
			memoFrontier[m] = frontier;
			memoKeys[keyBase] = s;
			memoKeys[keyBase + 1] = p;
			memoKeys[keyBase + 2] = o;
			memoKeys[keyBase + 3] = c;
			memoValid[m] = true;
			return frontier;
		}

		/** Computes and intersects the member frontiers under the current prefix. False when empty. */
		boolean enter(LeapfrogCursor cursor, RowState row) throws IOException {
			release(row);
			long[] intersection = null;
			long[] mult = null;
			for (int m = 0; m < members.length; m++) {
				PatternPlan member = cursor.plan.patterns[members[m]];
				boolean needCounts = finalLevel[m] && mayMatchMultipleQuads(member);
				Frontier frontier = memberFrontier(cursor, row, m, member, needCounts);
				if (frontier.values.length == 0) {
					values = Frontier.EMPTY_VALUES;
					multiplicities = null;
					position = -1;
					return false;
				}
				if (intersection == null) {
					intersection = frontier.values;
					mult = frontier.counts;
				} else {
					long[] merged = new long[Math.min(intersection.length, frontier.values.length)];
					long[] mergedMult = new long[merged.length];
					int out = 0;
					int i = 0;
					int j = 0;
					while (i < intersection.length && j < frontier.values.length) {
						int cmp = Long.compareUnsigned(intersection[i], frontier.values[j]);
						if (cmp == 0) {
							merged[out] = intersection[i];
							long left = mult == null ? 1 : mult[i];
							long right = frontier.counts == null ? 1 : frontier.counts[j];
							mergedMult[out] = left * right;
							out++;
							i++;
							j++;
						} else if (cmp < 0) {
							i = gallopTo(intersection, i + 1, frontier.values[j]);
						} else {
							j = gallopTo(frontier.values, j + 1, intersection[i]);
						}
					}
					intersection = Arrays.copyOf(merged, out);
					mult = Arrays.copyOf(mergedMult, out);
				}
				if (intersection.length == 0) {
					break;
				}
			}
			values = intersection;
			multiplicities = mult;
			position = -1;
			return values.length > 0;
		}

		/** First index at or after {@code from} whose value is unsigned-≥ {@code target} (galloping search). */
		private static int gallopTo(long[] values, int from, long target) {
			int bound = 1;
			int lo = from;
			int hi = from;
			while (hi < values.length && Long.compareUnsigned(values[hi], target) < 0) {
				lo = hi + 1;
				hi = from + bound;
				bound <<= 1;
			}
			hi = Math.min(hi, values.length);
			while (lo < hi) {
				int mid = (lo + hi) >>> 1;
				if (Long.compareUnsigned(values[mid], target) < 0) {
					lo = mid + 1;
				} else {
					hi = mid;
				}
			}
			return lo;
		}

		boolean advance(RowState row) {
			release(row);
			if (values == null) {
				return false;
			}
			while (true) {
				position++;
				if (position >= values.length) {
					return false;
				}
				mark = row.mark();
				if (row.bind(slot, values[position]) && passesFilters(row)) {
					return true;
				}
				row.rollback(mark);
				mark = -1;
			}
		}

		private boolean passesFilters(RowState row) {
			if (filters == null) {
				return true;
			}
			for (NativeBooleanFilter filter : filters) {
				if (!filter.accept(row)) {
					return false;
				}
			}
			return true;
		}

		long currentMultiplicity() {
			return multiplicities == null ? 1 : multiplicities[position];
		}

		void release(RowState row) {
			if (mark >= 0) {
				row.rollback(mark);
				mark = -1;
			}
		}
	}

	/** Sorted distinct candidate values (and optional duplicate counts) of one pattern position under a prefix. */
	private static final class Frontier {
		static final long[] EMPTY_VALUES = new long[0];
		final long[] values;
		final long[] counts;

		Frontier(long[] values, long[] counts) {
			this.values = values;
			this.counts = counts;
		}
	}

	/** Whether one visible binding of this pattern can be backed by several stored quads (hidden context). */
	private static boolean mayMatchMultipleQuads(PatternPlan pattern) {
		if (pattern.c.hasSlot() || pattern.c.isConstant()) {
			return false;
		}
		return !pattern.contexts.isFixed() || pattern.contexts.ids.length > 1;
	}

	/**
	 * One bounded scan collecting the distinct values at {@code slot}'s quad position given the pattern's currently
	 * bound terms. Values are sorted in unsigned id order; duplicate counts are collected when requested.
	 */
	private static Frontier scanFrontier(PatternPlan pattern, int slot, RowState row, boolean needCounts,
			NativeLmdbQuerySource.NativeProbe probe) throws IOException {
		int quadPosition = pattern.quadPositionOfSlot(slot);
		long[] collected = new long[16];
		int size = 0;
		try (PatternCursor cursor = pattern.openRaw(row, probe)) {
			long[] quad;
			while ((quad = cursor.next()) != null) {
				if (size == collected.length) {
					collected = Arrays.copyOf(collected, size << 1);
				}
				collected[size++] = quad[quadPosition];
			}
		}
		if (size == 0) {
			return new Frontier(Frontier.EMPTY_VALUES, null);
		}
		long[] values = Arrays.copyOf(collected, size);
		unsignedSort(values);
		int distinct = 0;
		long[] counts = needCounts ? new long[size] : null;
		for (int i = 0; i < size; i++) {
			if (distinct > 0 && values[distinct - 1] == values[i]) {
				if (counts != null) {
					counts[distinct - 1]++;
				}
				continue;
			}
			values[distinct] = values[i];
			if (counts != null) {
				counts[distinct] = 1;
			}
			distinct++;
		}
		long[] resultValues = distinct == size ? values : Arrays.copyOf(values, distinct);
		long[] resultCounts = counts == null ? null : Arrays.copyOf(counts, distinct);
		return new Frontier(resultValues, resultCounts);
	}

	/** In-place unsigned ascending sort (matches LMDB key order for ids). */
	private static void unsignedSort(long[] values) {
		for (int i = 0; i < values.length; i++) {
			values[i] ^= Long.MIN_VALUE;
		}
		Arrays.sort(values);
		for (int i = 0; i < values.length; i++) {
			values[i] ^= Long.MIN_VALUE;
		}
	}

	/**
	 * Parallel execution of one leapfrog run: the query thread's already-intersected first-level candidate array is
	 * tiled into index ranges; each worker binds candidates from its ranges on its own snapshot-sibling source and row
	 * state, runs the remaining levels with a worker-local serial leapfrog (own frontier cache and probes), and emits
	 * solution rows — the values of every originally-free core slot, one row per solution occurrence — through a
	 * bounded queue that the query thread binds back into the shared row. Unordered by design; downstream operators
	 * that need order sort afterwards, exactly as with the other unordered strategies.
	 */
	private static final class ParallelLeapfrog implements AutoCloseable {
		private static final int DEFAULT_PARALLEL_MIN_CANDIDATES = 1024;
		private static final boolean DEBUG = Boolean.getBoolean("rdf4j.lmdb.wcoj.debugParallel");
		private static final int RANGES_PER_WORKER = 4;
		private static final int PAGE_ROWS = 512;

		private final RowState consumerRow;
		private final int[] freeSlots;
		private final java.util.concurrent.ArrayBlockingQueue<long[]> output;
		private final java.util.concurrent.atomic.AtomicReference<Throwable> failure = new java.util.concurrent.atomic.AtomicReference<>();
		private final java.util.concurrent.atomic.AtomicBoolean cancelled = new java.util.concurrent.atomic.AtomicBoolean();
		private final java.util.concurrent.CountDownLatch tasks;
		private final LmdbNativeParallelPipelines.TaskReservation reservation;
		private final NativeLmdbQuerySource.ParallelSource[] sources;
		private final int workers;
		private long[] activePage;
		private int activeRows;
		private int activeIndex;
		private int consumerMark = -1;
		private boolean exhausted;

		/** A page is a flat row buffer; the first array element is the row count, rows follow densely. */
		private static long[] newPage(int width) {
			return new long[1 + width * PAGE_ROWS];
		}

		static ParallelLeapfrog tryStart(LeapfrogPlan plan, RowState row, Level[] levels, MaskedFilter[] filters)
				throws IOException {
			boolean debug = DEBUG;
			int candidates = levels[0].values.length;
			int minCandidates = Integer.getInteger(PARALLEL_MIN_CANDIDATES_PROPERTY, DEFAULT_PARALLEL_MIN_CANDIDATES);
			if (candidates < Math.max(1, minCandidates)) {
				if (debug) {
					System.err.println("[wcoj] parallel declined: candidates=" + candidates);
				}
				return null;
			}
			int desiredWorkers = LmdbNativeParallelPipelines.configuredThreads();
			if (desiredWorkers < 2) {
				if (debug) {
					System.err.println("[wcoj] parallel declined: threads=" + desiredWorkers);
				}
				return null;
			}
			LmdbNativeParallelPipelines.TaskReservation reservation = LmdbNativeParallelPipelines
					.tryReserveTasks(false, desiredWorkers);
			if (reservation == null || reservation.grantedWorkers() < 2) {
				if (debug) {
					System.err.println("[wcoj] parallel declined: reservation="
							+ (reservation == null ? "null" : reservation.grantedWorkers()));
				}
				if (reservation != null) {
					reservation.close();
				}
				return null;
			}
			int workers = reservation.grantedWorkers();
			// worker-confined filter forks; any unforkable filter keeps the whole run serial
			MaskedFilter[][] workerFilters = new MaskedFilter[workers][];
			for (int w = 0; w < workers; w++) {
				workerFilters[w] = new MaskedFilter[filters.length];
				for (int f = 0; f < filters.length; f++) {
					NativeBooleanFilter fork = filters[f].filter.forkForParallelWorker();
					if (fork == null) {
						if (debug) {
							NativeBooleanFilter unforkable = filters[f].filter;
							String detail = unforkable instanceof RecordingNativeBooleanFilter recording
									? recording.delegate.getClass().getName()
									: unforkable.getClass().getName();
							System.err.println("[wcoj] parallel declined: unforkable filter " + detail);
						}
						closeWorkerFilters(workerFilters, null);
						reservation.close();
						return null;
					}
					workerFilters[w][f] = new MaskedFilter(fork, filters[f].mask,
							AdaptiveFilterMetadata.missing(), -1);
				}
			}
			NativeLmdbQuerySource.ParallelSource[] sources;
			try {
				sources = row.source.openParallelSources(workers);
			} catch (IOException | RuntimeException | Error problem) {
				closeWorkerFilters(workerFilters, null);
				reservation.close();
				throw problem;
			}
			if (sources == null || sources.length < workers) {
				if (debug) {
					System.err.println("[wcoj] parallel declined: sources="
							+ (sources == null ? "null" : sources.length) + " workers=" + workers);
				}
				closeSources(sources);
				closeWorkerFilters(workerFilters, null);
				reservation.close();
				return null;
			}
			PARALLEL_RUNS.incrementAndGet();
			if (debug) {
				System.err.println("[wcoj] parallel engaged: candidates=" + candidates + " workers=" + workers);
			}
			return new ParallelLeapfrog(plan, row, levels, reservation, sources, workers, workerFilters);
		}

		private static void closeWorkerFilters(MaskedFilter[][] workerFilters, Throwable primary) {
			if (workerFilters == null) {
				return;
			}
			for (MaskedFilter[] filters : workerFilters) {
				if (filters == null) {
					continue;
				}
				for (MaskedFilter filter : filters) {
					if (filter != null) {
						try {
							filter.filter.close();
						} catch (RuntimeException | Error problem) {
							if (primary != null && primary != problem) {
								primary.addSuppressed(problem);
							}
						}
					}
				}
			}
		}

		private ParallelLeapfrog(LeapfrogPlan plan, RowState row, Level[] levels,
				LmdbNativeParallelPipelines.TaskReservation reservation,
				NativeLmdbQuerySource.ParallelSource[] sources, int workers, MaskedFilter[][] workerFilters) {
			this.consumerRow = row;
			this.reservation = reservation;
			this.sources = sources;
			this.workers = workers;
			this.freeSlots = new int[levels.length];
			for (int d = 0; d < levels.length; d++) {
				this.freeSlots[d] = levels[d].slot;
			}
			this.output = new java.util.concurrent.ArrayBlockingQueue<>(workers * 2);
			this.tasks = new java.util.concurrent.CountDownLatch(workers);

			long[] candidates = levels[0].values;
			long[] candidateMults = levels[0].multiplicities;
			int firstSlot = levels[0].slot;
			long[] entrySlots = Arrays.copyOf(row.slots, row.slots.length);

			int rangeCount = Math.min(candidates.length, workers * RANGES_PER_WORKER);
			java.util.concurrent.ConcurrentLinkedQueue<int[]> ranges = new java.util.concurrent.ConcurrentLinkedQueue<>();
			for (int r = 0; r < rangeCount; r++) {
				int from = (int) ((long) candidates.length * r / rangeCount);
				int to = (int) ((long) candidates.length * (r + 1) / rangeCount);
				if (from < to) {
					ranges.add(new int[] { from, to });
				}
			}
			int submitted = 0;
			try {
				for (int w = 0; w < workers; w++) {
					NativeLmdbQuerySource.ParallelSource workerSource = sources[w];
					MaskedFilter[] ownFilters = workerFilters[w];
					java.util.concurrent.Future<?> ignored = LmdbNativeParallelPipelines.pool()
							.submit(() -> runWorker(plan, workerSource, ownFilters, entrySlots, firstSlot, candidates,
									candidateMults, ranges));
					submitted++;
				}
			} finally {
				for (int w = submitted; w < workers; w++) {
					closeWorkerFilters(new MaskedFilter[][] { workerFilters[w] }, null);
					try {
						sources[w].close();
					} catch (RuntimeException | Error ignoredProblem) {
						// startup failure path; the primary failure propagates from the submit call
					}
					tasks.countDown();
				}
				if (submitted < workers) {
					cancelled.set(true);
				}
			}
		}

		private void runWorker(LeapfrogPlan sharedPlan, NativeLmdbQuerySource.ParallelSource workerSource,
				MaskedFilter[] ownFilters, long[] entrySlots, int firstSlot, long[] candidates, long[] candidateMults,
				java.util.concurrent.ConcurrentLinkedQueue<int[]> ranges) {
			try (workerSource) {
				// the plan and its frontier cache are shared: cached frontiers are immutable, and worker scans
				// happen against snapshot-sibling sources of the same store snapshot
				LeapfrogPlan workerPlan = sharedPlan;
				RowState workerRow = new RowState(workerSource, consumerRow.layout, consumerRow.base);
				for (int i = 0; i < entrySlots.length; i++) {
					workerRow.slots[i] = entrySlots[i];
				}
				workerRow.recomputeBoundMask();
				int width = freeSlots.length;
				long[] page = newPage(width);
				int rows = 0;
				int[] range;
				while ((range = ranges.poll()) != null && !cancelled.get()) {
					for (int i = range[0]; i < range[1] && !cancelled.get(); i++) {
						long candidate = candidates[i];
						long candidateMultiplicity = candidateMults == null ? 1 : candidateMults[i];
						int mark = workerRow.mark();
						if (!workerRow.bind(firstSlot, candidate)) {
							workerRow.rollback(mark);
							continue;
						}
						try (LeapfrogCursor cursor = new LeapfrogCursor(workerPlan, workerRow, false, ownFilters)) {
							while (cursor.next()) {
								for (long m = 0; m < candidateMultiplicity; m++) {
									int base = 1 + rows * width;
									for (int s = 0; s < width; s++) {
										page[base + s] = workerRow.slots[freeSlots[s]];
									}
									rows++;
									if (rows == PAGE_ROWS) {
										page[0] = rows;
										publish(page);
										page = newPage(width);
										rows = 0;
									}
								}
							}
						}
						workerRow.rollback(mark);
					}
				}
				if (rows > 0 && !cancelled.get()) {
					page[0] = rows;
					publish(page);
				}
			} catch (Throwable problem) {
				if (failure.compareAndSet(null, problem)) {
					cancelled.set(true);
				}
			} finally {
				closeWorkerFilters(new MaskedFilter[][] { ownFilters }, failure.get());
				taskFinished();
			}
		}

		private void publish(long[] page) throws InterruptedException {
			while (!cancelled.get()) {
				if (output.offer(page, 50, java.util.concurrent.TimeUnit.MILLISECONDS)) {
					return;
				}
			}
		}

		private void taskFinished() {
			tasks.countDown();
			if (tasks.getCount() == 0) {
				reservation.close();
			}
		}

		boolean next() throws IOException {
			releaseRow();
			while (true) {
				if (activePage != null && activeIndex < activeRows) {
					int width = freeSlots.length;
					int base = 1 + activeIndex * width;
					activeIndex++;
					consumerMark = consumerRow.mark();
					boolean bound = true;
					for (int s = 0; s < width; s++) {
						long value = page(base + s);
						if (value != UNKNOWN && !consumerRow.bind(freeSlots[s], value)) {
							bound = false;
							break;
						}
					}
					if (bound) {
						return true;
					}
					releaseRow();
					continue;
				}
				activePage = null;
				if (exhausted) {
					return false;
				}
				propagateFailure();
				// read the latch BEFORE checking the queue: publish happens-before countdown, so once the
				// count is zero no further pages can appear and an empty queue means fully drained
				boolean allDone = tasks.getCount() == 0;
				long[] page = output.poll();
				if (page == null) {
					if (allDone) {
						propagateFailure();
						exhausted = true;
						return false;
					}
					try {
						page = output.poll(2, java.util.concurrent.TimeUnit.MILLISECONDS);
					} catch (InterruptedException e) {
						Thread.currentThread().interrupt();
						throw new IOException(e);
					}
					if (page == null) {
						continue;
					}
				}
				activePage = page;
				activeRows = (int) page[0];
				activeIndex = 0;
			}
		}

		private long page(int index) {
			return activePage[index];
		}

		private void releaseRow() {
			if (consumerMark >= 0) {
				consumerRow.rollback(consumerMark);
				consumerMark = -1;
			}
		}

		private void propagateFailure() throws IOException {
			Throwable problem = failure.get();
			if (problem == null) {
				return;
			}
			cancelled.set(true);
			if (problem instanceof IOException io) {
				throw io;
			}
			if (problem instanceof RuntimeException runtime) {
				throw runtime;
			}
			if (problem instanceof Error error) {
				throw error;
			}
			throw new IOException(problem);
		}

		@Override
		public void close() {
			releaseRow();
			cancelled.set(true);
			output.clear();
			boolean interrupted = false;
			while (tasks.getCount() > 0) {
				output.clear();
				try {
					tasks.await(50, java.util.concurrent.TimeUnit.MILLISECONDS);
				} catch (InterruptedException e) {
					interrupted = true;
				}
			}
			if (interrupted) {
				Thread.currentThread().interrupt();
			}
		}

		private static void closeSources(NativeLmdbQuerySource.ParallelSource[] sources) {
			if (sources == null) {
				return;
			}
			for (NativeLmdbQuerySource.ParallelSource source : sources) {
				if (source != null) {
					source.close();
				}
			}
		}
	}
}
